// ──────────────────────────────────────────────────────────────
// دالة البحث الذكية المحسنة (إصلاح تطابق الكلمات + دعم اسم المستخدم)
// ──────────────────────────────────────────────────────────────

/**
 * دالة البحث الذكية - تدعم استبدال {userName} ديناميكياً
 * @param {string} userText - نص سؤال المستخدم
 * @param {string} userName - اسم المستخدم (اختياري، الافتراضي: 'غالي')
 * @returns {string} - الرد المناسب مع استبدال اسم المستخدم
 */
export function getBotReply(userText, userName = 'غالي') {
  if (!userText || typeof userText !== 'string') {
    return "عذراً يا {userName}، ما فهمت السؤال تماماً. تقدر تعيد صياغته؟ 🤔".replace(/{userName}/g, userName);
  }

  let text = userText.toLowerCase().trim();
  
  // كلمات البداية الشائعة لإزالتها
  const stopWords = [];
  let cleanedText = text;
  
  // تنظيف متكرر من كلمات البداية
  let changed = true;
  while (changed) {
    changed = false;
    for (let word of stopWords) {
      const regex = new RegExp(`^${word}\\s+`, 'i');
      if (regex.test(cleanedText) || cleanedText === word) {
        cleanedText = cleanedText.replace(regex, '').trim();
        changed = true;
        break;
      }
    }
  }

  let bestMatch = null;
  let maxScore = 0;

  // 🔧 ترتيب العناصر: الكلمات الأطول أولاً (لأولوية المطابقة الدقيقة)
  const sortedDB = [...RESPONSES_DB].sort((a, b) => {
    const aMaxLen = Math.max(...a.keywords.map(k => k.length));
    const bMaxLen = Math.max(...b.keywords.map(k => k.length));
    return bMaxLen - aMaxLen;
  });

  for (const item of sortedDB) {
    let score = 0;
    let matchedKeywordsCount = 0;

    for (const keyword of item.keywords) {
      const kwLower = keyword.toLowerCase();
      
      const matchesOriginal = text.includes(kwLower);
      const matchesCleaned = cleanedText.includes(kwLower);
      
      if (matchesOriginal || matchesCleaned) {
        // 🔧 وزن أكبر للكلمات الأطول (أكثر تحديداً)
        score += kwLower.length * 2;
        
        // بونص إذا كانت الكلمة في البداية أو النهاية
        if (text.startsWith(kwLower) || text.endsWith(kwLower) || cleanedText.startsWith(kwLower) || cleanedText.endsWith(kwLower)) {
          score += 5;
        }
        
        // 🔧 تحسين: تجنب تطابق "ري" داخل "اشتري"
        // نستخدم تطابق كلمة كاملة بسيط للعربية
        const pattern = `(^|\\s)${kwLower.replace(/[.*+?^${}()|[\\]\\]/g, '\\$&')}($|\\s)`;
        const wordRegex = new RegExp(pattern, 'i');
        if (wordRegex.test(` ${text} `) || wordRegex.test(` ${cleanedText} `)) {
          score += 4;
        }
        
        matchedKeywordsCount++;
      }
    }

    // بونص إضافي لتعدد الكلمات المتطابقة
    if (matchedKeywordsCount > 1) {
      score += (matchedKeywordsCount * 3);
    }

    // 🔧 بونص إضافي للكلمة الأطول في المجموعة
    const longestKeyword = item.keywords.reduce((a, b) => a.length > b.length ? a : b, '');
    if (text.includes(longestKeyword.toLowerCase()) || cleanedText.includes(longestKeyword.toLowerCase())) {
      score += 10;
    }

    if (score > maxScore) {
      maxScore = score;
      bestMatch = item;
    }
  }

  // 🔧 خفض العتبة قليلاً مع الحفاظ على الدقة
  if (bestMatch && maxScore >= 4) {
    // ✅ استبدال {userName} بالاسم الفعلي في الرد
    return bestMatch.reply.replace(/{userName}/g, userName);
  }

  // رد افتراضي مع اقتراحات
  const fallbackSuggestions = [
    "🔹 'أبي فني تكييف' أو 'أبي فني كهرباء'",
    "🔹 'وش أسعار قطع الغيار؟'",
    "🔹 'كيف أطلب من المتجر؟'",
    "🔹 'عندي مشكلة في المكيف' أو 'عندي مشكلة كهرباء'",
    "🔹 'وش التخصصات اللي عندكم؟'"
  ];
  
  return `عذراً يا {userName}، ما اتضحت لي الصورة تماماً! 🤔\nأنا مساعد متخصص في الصيانة وقطع الغيار والتطبيق.\n\nجرب تسألني مثلاً:\n${fallbackSuggestions.join('\n')}\n\nأو اكتب لي المشكلة بالتفصيل، وأنا أفهمك بإذن الله! 😊\n(تبي تختصر؟ اكتب "اختصار" لأجيبك بسرعة ⚡)`.replace(/{userName}/g, userName);
}

export function getNavigationIntent(userText) {
  if (!userText || typeof userText !== 'string') return null;
  const text = userText.toLowerCase();
  for (const [screen, keywords] of Object.entries(NAV_KEYWORDS)) {
    for (const keyword of keywords) {
      if (text.includes(keyword.toLowerCase())) {
        return screen;
      }
    }
  }
  return null;
}

export function isYesResponse(text) {
  if (!text) return false;
  const t = text.trim().toLowerCase();
  return /^(نعم|ايوه|أيوه|اه|آه|أه|صح|بلى|yes|اوك|تمام|ماشي|يلا|أكيد|بالطبع|أبشر|هه|حاضر|توكل|تفضل|هيا|يابه|تمام تمام|يوه|آيوه)$/i.test(t);
}

export function isNoResponse(text) {
  if (!text) return false;
  const t = text.trim().toLowerCase();
  return /^(لا|لأ|لاء|no|ما|مو|مش|ابدا|لا شكراً|لا أبشر|بعدين|مش الحين|لا تبي|ما أبي|مو لازم|لازم لا|استنى|ثواني|بعدين شوي)$/i.test(t);
}

export { NAV_SCREENS, RESPONSES_DB };